using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int size) : size(size), tree(size + 2, 0) {}
    void update(int index, long long delta) {
        index += 1; // 1-based index
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        index += 1; // 1-based index
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

int get_depth(long long x) {
    int depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
    }
    return depth;
}

