        depths[i] = get_depth(nums[i]);
    }
    vector<FenwickTree> ft(4);
    for (int i = 0; i < 4; ++i) {
        ft[i] = FenwickTree(n);
    }
    for (int i = 0; i < n; ++i) {
        int d = depths[i];
        ft[d].update(i, 1);
    }
